import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import PondChartCard from '../../components/charts/PondChartCard' // Import đồng bộ component chart
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: '1', label: 'Xử lý ao (POND_PROCESS)' },
  { value: '2', label: 'Cho ăn (FEEDING)' },
  { value: '3', label: 'Cho thuốc (TREATMENT)' },
  { value: '4', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: '5', label: 'Thu hoạch (HARVEST)' },
  { value: '6', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA STATE =====
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])
  const [matrixPonds, setMatrixPonds] = useState([])

  // ===== UI STATE =====
  const [loading, setLoading] = useState(true)
  const [loadingPonds, setLoadingPonds] = useState(false)
  const [currentPage, setCurrentPage] = useState(1)
  const [pageSize, setPageSize] = useState(10)
  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  
  // Trạng thái các bộ lọc lọc ngoài bảng (Đồng bộ cách đặt tên và logic)
  const [filterType, setFilterType] = useState('')
  const [filterPond, setFilterPond] = useState('')
  const [filterSeason, setFilterSeason] = useState('')
  const [filterWorker, setFilterWorker] = useState('')
  const [filterStatus, setFilterStatus] = useState('ALL')

  // Lấy danh sách mùa vụ duy nhất từ tasks
  const seasons = useMemo(() => {
    const unique = [...new Set(tasks.map(t => t.season_id).filter(Boolean))];
    return unique.map(id => ({
      id,
      name: tasks.find(t => t.season_id === id)?.season_name || `Mùa vụ ${id}`
    }));
  }, [tasks]);

  // ===== FORM STATE (HỖ TRỢ MA TRẬN) =====
  const initialForm = {
    task_type: '',
    assignments: [],
    task_title: '',
    description: '',
    start_date: '',
    due_date: '',
    product_id: '',
    quantity: '',
  }
  const [form, setForm] = useState(initialForm)

  // ==========================================
  // LOGIC TỰ ĐỘNG ĐÁNH GIÁ QUÁ HẠN (REALTIME)
  // ==========================================
  const getComputedStatus = (task) => {
    const baseStatus = normalize(task.status)
    if (['COMPLETED', 'CANCELLED'].includes(baseStatus)) {
      return baseStatus
    }
    if (task.due_date && new Date(task.due_date) < new Date()) {
      return 'OVERDUE'
    }
    return baseStatus
  }

  const getStatusLabel = (statusValue) => {
    const computed = normalize(statusValue)
    switch (computed) {
      case 'PENDING': return 'Chờ xử lý'
      case 'IN_PROGRESS': return 'Đang thực hiện'
      case 'COMPLETED': return 'Hoàn thành'
      case 'CANCELLED': return 'Đã hủy'
      case 'OVERDUE': return 'Quá hạn'
      default: return statusValue || '-'
    }
  }

  const getStatusBadgeClass = (task) => {
    const computed = getComputedStatus(task)
    switch (computed) {
      case 'IN_PROGRESS': return 'technician-ponds_status technician-ponds_status--farming'
      case 'PENDING': return 'technician-ponds_status technician-ponds_status--paused'
      case 'COMPLETED': return 'technician-ponds_status technician-ponds_status--renovating'
      case 'CANCELLED': return 'technician-ponds_status bg-gray-400 text-white'
      case 'OVERDUE': return 'technician-ponds_status bg-red-500 text-white font-bold'
      default: return 'technician-ponds_status bg-slate-500 text-white'
    }
  }

  // =========================
  // FETCH DATA FROM API
  // =========================
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách công việc', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh mục sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkersStatus = useCallback(async () => {
    try {
      const res = await taskService.getWorkersStatus()
      setWorkers(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được trạng thái nhân công', type: 'error' })
    }
  }, [])

  useEffect(() => {
    const loadInitialData = async () => {
      setLoading(true)
      try {
        await Promise.all([
          fetchTasks(),
          fetchProducts(),
          fetchWorkersStatus()
        ])
        const pondRes = await taskService.getPondsByType('OTHER')
        setPonds(pondRes?.data?.data || [])
      } catch (err) {
        console.error("Lỗi khi tải dữ liệu khởi tạo:", err)
      } finally {
        setLoading(false)
      }
    }
    loadInitialData()
  }, [fetchTasks, fetchProducts, fetchWorkersStatus])

  const handleTypeChange = async (e) => {
    const typeCode = e.target.value ? e.target.value.trim().toUpperCase() : ''
    setForm(prev => ({
      ...prev,
      task_type: typeCode,
      assignments: [],
      product_id: '',
      quantity: ''
    }))
    setMatrixPonds([])

    if (!typeCode) return

    setLoadingPonds(true)
    try {
      const res = await taskService.getPondsByType(typeCode)
      setMatrixPonds(res?.data?.data || [])
    } catch (err) {
      showToast({ title: 'Lỗi khi tự động lọc danh sách ao tương ứng', type: 'error' })
    } finally {
      setLoadingPonds(false)
    }
  }

  const toggleAssignment = (workerId, pondId) => {
    setForm(prev => {
      const isAlreadyChecked = prev.assignments.some(a => a.worker_id === workerId && a.pond_id === pondId);
      if (isAlreadyChecked) {
        return {
          ...prev,
          assignments: prev.assignments.filter(a => !(a.worker_id === workerId && a.pond_id === pondId))
        };
      }
      const otherTasks = prev.assignments.filter(a => a.worker_id !== workerId);
      return {
        ...prev,
        assignments: [...otherTasks, { worker_id: workerId, pond_id: pondId }]
      };
    });
  };

  // ==========================================
  // COMPUTE STATS AND CHARTS DATA (ĐỒNG BỘ SEASONS)
  // ==========================================
  const stats = useMemo(() => {
    const computedTasks = tasks.map(t => ({ ...t, computedStatus: getComputedStatus(t) }))
    return {
      total: computedTasks.length,
      pending: computedTasks.filter(t => t.computedStatus === 'PENDING').length,
      progress: computedTasks.filter(t => t.computedStatus === 'IN_PROGRESS').length,
      completed: computedTasks.filter(t => t.computedStatus === 'COMPLETED').length,
      overdue: computedTasks.filter(t => t.computedStatus === 'OVERDUE').length,
    }
  }, [tasks])

  const taskStatusChartData = [
    { label: 'Chờ xử lý', value: stats.pending, color: '#f59e0b' },
    { label: 'Đang thực hiện', value: stats.progress, color: '#3b82f6' },
    { label: 'Hoàn thành', value: stats.completed, color: '#22c55e' },
    { label: 'Quá hạn', value: stats.overdue, color: '#ef4444' },
  ]

  const taskTypeChartData = useMemo(() => {
    const typeCounts = {}
    tasks.forEach(t => {
      const typeLabel = t.type_name || t.task_type || 'Khác'
      typeCounts[typeLabel] = (typeCounts[typeLabel] || 0) + 1
    })
    const colorPalette = ['#3b82f6', '#06b6d4', '#7c3aed', '#ef4444', '#f59e0b', '#10b981']
    return Object.keys(typeCounts).map((key, idx) => ({
      label: key,
      value: typeCounts[key],
      color: colorPalette[idx % colorPalette.length]
    }))
  }, [tasks])

  // =========================
  // FILTER & PAGINATION LOGIC
  // =========================
  const filteredTasks = useMemo(() => {
    return tasks.filter(task => {
      const matchType = !filterType || String(task.type_id) === String(filterType);
      const matchPond = !filterPond || String(task.pond_id) === String(filterPond);
      const matchSeason = !filterSeason || String(task.season_id) === String(filterSeason);
      const matchWorker = !filterWorker || (
        task.assigned_workers_list && 
        task.assigned_workers_list.some(w => String(w.worker_id) === String(filterWorker))
      );
      const matchStatus = filterStatus === 'ALL' || String(getComputedStatus(task)) === String(filterStatus);

      return matchType && matchPond && matchSeason && matchWorker && matchStatus;
    });
  }, [tasks, filterType, filterPond, filterSeason, filterWorker, filterStatus]);

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize))
  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filteredTasks.length)
  const paginatedTasks = filteredTasks.slice(startIndex, endIndex)

  const isProductRequired = useMemo(() => {
    return ['FEEDING', 'TREATMENT', 'POND_PROCESS'].includes(form.task_type)
  }, [form.task_type])

  const handleCreateTask = async () => {
    if (!form.assignments || form.assignments.length === 0) {
      showToast({ title: 'Vui lòng chọn ít nhất một phân công trong ma trận', type: 'warning' })
      return
    }
    if (!form.description?.trim()) {
      showToast({ title: 'Vui lòng nhập hướng dẫn kỹ thuật', type: 'warning' })
      return
    }

    const confirmAction = window.confirm(`Xác nhận tạo ${form.assignments.length} dòng công việc độc lập cho các cặp nhân công-ao đã chọn?`)
    if (!confirmAction) return

    setLoading(true)
    try {
      let finalTitle = form.task_title?.trim()
      if (!finalTitle) {
        const typeOpt = TASK_TYPE_OPTIONS.find(o => o.value === form.task_type)
        finalTitle = typeOpt ? `Công tác ${typeOpt.label}` : 'Công việc kỹ thuật'
      }

      const TASK_TYPE_MAP_ID = { 'POND_PROCESS': 1, 'FEEDING': 2, 'TREATMENT': 3, 'ENVIRONMENTAL_CHECK': 4, 'HARVEST': 5, 'OTHER': 6 }
      const currentNumericTypeId = TASK_TYPE_MAP_ID[form.task_type] || 6

      for (const assignment of form.assignments) {
        const selectedPondObj = matrixPonds.find(p => Number(p.pond_id) === Number(assignment.pond_id))

        const singleTaskData = {
          type_id: Number(currentNumericTypeId),
          task_type: form.task_type,
          pond_id: Number(assignment.pond_id),
          task_title: finalTitle,
          description: form.description,
          start_date: form.start_date,
          due_date: form.due_date,
          assigned_workers: [Number(assignment.worker_id)]
        }

        if (selectedPondObj?.season_id) singleTaskData.season_id = Number(selectedPondObj.season_id)
        if (isProductRequired && form.product_id) {
          singleTaskData.product_id = Number(form.product_id)
          singleTaskData.quantity = parseFloat(form.quantity) || 0
        }

        await taskService.createTask(singleTaskData)
      }

      showToast({ title: `Đã tạo thành công ${form.assignments.length} dòng công việc!`, type: 'success' })
      setForm(initialForm)
      setIsCreateOpen(false)
      await fetchTasks()
    } catch (err) {
      showToast({ title: 'Có lỗi khi tạo task: ' + (err.response?.data?.message || 'Lỗi server'), type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  const handleCancelTask = async (taskId) => {
    const confirmCancel = window.confirm("Bạn có chắc chắn muốn HỦY bỏ hoàn toàn công việc này không?")
    if (!confirmCancel) return

    try {
      await taskService.cancelTask(taskId)
      showToast({ title: 'Đã hủy công việc thành công', type: 'success' })
      setSelectedTask(null)
      await Promise.all([fetchTasks(), fetchWorkersStatus()])
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Không thể hủy công việc', type: 'error' })
    }
  }

  const getAssignedWorkersName = (task) => {
    if (task.assigned_workers_list && Array.isArray(task.assigned_workers_list)) {
      return task.assigned_workers_list.map(w => w.full_name).join(', ');
    }
    return 'Chưa phân công';
  };

  if (loading) {
    return (
      <div className="dashboard admin-page technician-tasks_page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard admin-page technician-ponds technician-seasons_page technician-tasks_page">
      <div className="table-container table-panel">
        
        {/* MAIN HEADER (ĐỒNG BỘ GIỐNG POND/SEASONS) */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Giám sát và phân phối ma trận việc làm cho Công nhân kỹ thuật</p>
          </div>
          <button type="button" className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
            + Phân công việc (Hệ Ma trận)
          </button>
        </div>

        {/* OVERVIEW STATS CARDS BLOCK */}
        <div className="stats-grid">
          <div className="stats-card stats-card--primary">
            <span className="stats-card-label">Tổng công việc</span>
            <strong className="stats-card-value">{stats.total}</strong>
          </div>
          <div className="stats-card stats-card--warning">
            <span className="stats-card-label">Chờ xử lý</span>
            <strong className="stats-card-value">{stats.pending}</strong>
          </div>
          <div className="stats-card stats-card--success">
            <span className="stats-card-label">Đang thực hiện</span>
            <strong className="stats-card-value">{stats.progress}</strong>
          </div>
          <div className="stats-card stats-card--info">
            <span className="stats-card-label">Hoàn thành</span>
            <strong className="stats-card-value">{stats.completed}</strong>
          </div>
          <div className="stats-card stats-card--neutral" style={{ borderLeftColor: '#ef4444' }}>
            <span className="stats-card-label" style={{ color: '#ef4444' }}>Quá hạn</span>
            <strong className="stats-card-value" style={{ color: '#ef4444' }}>{stats.overdue}</strong>
          </div>
        </div>

        {/* CHARTS SYSTEM BLOCK */}
        <div className="technician-ponds_charts-grid">
          <PondChartCard
            prefix="technician-ponds"
            title="Công việc theo trạng thái"
            type="bar"
            data={taskStatusChartData}
          />
          <PondChartCard
            prefix="technician-ponds"
            title="Tỷ lệ phân loại công việc"
            type="bar"
            data={taskTypeChartData}
          />
        </div>

        {/* TOOLBAR & FILTERS SYSTEM */}
        <div className="table-toolbar technician-ponds_toolbar">
          <select
            className="table-filter"
            value={filterType}
            onChange={(e) => { setFilterType(e.target.value); setCurrentPage(1); }}
          >
            <option value="">Tất cả loại công việc</option>
            {TASK_TYPE_OPTIONS.map((type) => (
              <option key={type.value} value={type.value}>{type.label}</option>
            ))}
          </select>

          <select className="table-filter" value={filterPond} onChange={(e) => { setFilterPond(e.target.value); setCurrentPage(1); }}>
            <option value="">Tất cả ao nuôi</option>
            {ponds.map(pond => (
              <option key={pond.pond_id} value={pond.pond_id}>{pond.pond_name}</option>
            ))}
          </select>

          <select className="table-filter" value={filterSeason} onChange={(e) => { setFilterSeason(e.target.value); setCurrentPage(1); }}>
            <option value="">Tất cả mùa vụ</option>
            {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>

          <select className="table-filter" value={filterWorker} onChange={(e) => { setFilterWorker(e.target.value); setCurrentPage(1); }}>
            <option value="">Tất cả nhân viên</option>
            {workers.map(w => <option key={w.worker_id} value={w.worker_id}>{w.full_name}</option>)}
          </select>

          <select className="table-filter" value={filterStatus} onChange={(e) => { setFilterStatus(e.target.value); setCurrentPage(1); }}>
            <option value="ALL">Tất cả trạng thái</option>
            {STATUS_OPTIONS.filter(s => s.value !== 'ALL').map(s => (
              <option key={s.value} value={s.value}>{s.label}</option>
            ))}
          </select>
        </div>

        {/* DATA TABLE WRAPPER */}
        <div className="table-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Loại công việc</th>
                <th>Ao nuôi</th>
                <th>Mùa vụ</th>
                <th>Người thực hiện</th>
                <th>Hạn hoàn thành</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {paginatedTasks.length === 0 ? (
                <tr>
                  <td className="table-empty-row" colSpan="7" style={{ textAlign: 'center', padding: '20px' }}>Không có dữ liệu...</td>
                </tr>
              ) : (
                paginatedTasks.map((t, idx) => (
                  <tr key={`task-row-${t.task_id || idx}`}>
                    <td>
                      <div className="technician-ponds_name-block">
                        <strong>{t.type_name || t.task_type}</strong>
                        <div style={{ fontSize: '0.85em', color: '#666' }}>{t.task_title}</div>
                      </div>
                    </td>
                    <td>{t.pond_name || '-'}</td>
                    <td>{t.season_name || '-'}</td>
                    <td>
                      <div className="worker-info-cell">
                        <strong>{getAssignedWorkersName(t)}</strong>
                      </div>
                    </td>
                    <td>{formatDate(t.due_date)}</td>
                    <td>
                      <span className={getStatusBadgeClass(t)}>
                        {getStatusLabel(getComputedStatus(t))}
                      </span>
                    </td>
                    <td>
                      <div className="table-actions">
                        <button type="button" className="table-action-btn table-action-btn--view" title="Xem chi tiết" onClick={() => setSelectedTask(t)}>
                          ⓘ
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* PAGINATION SYSTEM */}
        <div className="table-pagination">
          <div className="table-pagination-left">
            <span>Số mục trên trang</span>
            <select
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value) || 10)
                setCurrentPage(1)
              }}
            >
              {[5, 10, 20, 50].map((size) => (
                <option key={`page-size-${size}`} value={size}>{size}</option>
              ))}
            </select>
            <span>{filteredTasks.length === 0 ? 0 : startIndex + 1}-{endIndex} / {filteredTasks.length}</span>
          </div>

          <div className="table-pagination-right">
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage <= 1}
              onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            >
              ‹
            </button>
            <span className="table-page-pill">{safePage}</span>
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage >= totalPages}
              onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content technician-seasons_modal" onClick={(e) => e.stopPropagation()}>
            <h3 className="technician-seasons_modal-title">Chi tiết tiến độ công việc</h3>

            <div className="technician-seasons_detail-grid">
              <div><strong>Mã công việc:</strong> {selectedTask.task_code || '-'}</div>
              <div><strong>Loại công việc:</strong> {selectedTask.type_name || '-'}</div>
              <div><strong>Tiêu đề:</strong> {selectedTask.task_title || '-'}</div>
              <div><strong>Ao nuôi:</strong> {selectedTask.pond_name || '-'} (Mã: {selectedTask.pond_code || '-'})</div>
              <div><strong>Thời gian bắt đầu:</strong> {formatDate(selectedTask.start_date)}</div>
              <div><strong>Hạn chót:</strong> {formatDate(selectedTask.due_date)}</div>
              
              {selectedTask.completed_at && (
                <div>
                  <strong>Hoàn thành thực tế:</strong> 
                  <span style={{ color: 'green', marginLeft: '6px' }}>{formatDate(selectedTask.completed_at)}</span>
                </div>
              )}
              
              <div><strong>Nhân công phụ trách:</strong> {getAssignedWorkersName(selectedTask)}</div>
              
              <div>
                <strong>Trạng thái:</strong> 
                <span className={`${getStatusBadgeClass(selectedTask)}`} style={{ marginLeft: '8px' }}>
                  {getStatusLabel(getComputedStatus(selectedTask))}
                </span>
              </div>

              {selectedTask.product_info && (
                <div style={{ gridColumn: '1 / -1', background: '#e0f2fe', borderColor: '#bae6fd' }}>
                  <strong>Vật tư chỉ định:</strong> {selectedTask.product_info.product_name} — SL: {selectedTask.product_info.quantity} {selectedTask.product_info.unit || ''}
                </div>
              )}

              <div style={{ gridColumn: '1 / -1' }}>
                <strong>Hướng dẫn kỹ thuật:</strong>
                <p className="technical-instruction-text" style={{ marginTop: '6px', whiteSpace: 'pre-line' }}>{selectedTask.description || 'Không có hướng dẫn chi tiết.'}</p>
              </div>
            </div>

            {selectedTask.task_images && selectedTask.task_images.length > 0 && (
              <div style={{ marginTop: '16px' }}>
                <span style={{ fontWeight: '600', fontSize: '0.92rem' }}>Hình ảnh báo cáo thực địa:</span>
                <div className="task-images" style={{ display: 'flex', gap: '10px', marginTop: '8px' }}>
                  {selectedTask.task_images.map((imgUrl, i) => (
                    <img key={`task-img-${i}`} src={imgUrl} alt={`Ảnh ${i + 1}`} style={{ width: '80px', height: '80px', objectFit: 'cover', borderRadius: '8px', cursor: 'pointer' }} onClick={() => window.open(imgUrl, '_blank')} />
                  ))}
                </div>
              </div>
            )}

            <div className="technician-seasons_actions" style={{ marginTop: '20px', display: 'flex', justifyContent: 'space-between', width: '100%' }}>
              <div>
                {normalize(selectedTask.status) === 'PENDING' && (
                  <button type="button" className="btn btn-danger" onClick={() => handleCancelTask(selectedTask.task_id)}>
                    Hủy công việc
                  </button>
                )}
              </div>
              <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng lại</button>
            </div>
          </div>
        </div>
      )}

      {/* CREATE MATRIX TASK MODAL */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content technician-seasons_modal technician-seasons_modal--harvest" onClick={(e) => e.stopPropagation()}>
            <div className="matrix-modal-header" style={{ marginBottom: '16px' }}>
              <h3 className="technician-seasons_modal-title" style={{ margin: 0 }}>Phân công công việc Hệ Ma Trận</h3>
              <p style={{ fontSize: '0.88rem', color: '#64748b', margin: '4px 0 0' }}>Hệ thống tự động đồng bộ một nội dung hướng dẫn cho nhiều ao nuôi và nhóm nhân công được tích chọn.</p>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
              <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                <label>Loại công việc kỹ thuật <span style={{ color: 'red' }}>*</span></label>
                <select className="input" value={form.task_type} onChange={handleTypeChange}>
                  <option value="">-- Chọn loại công việc để kích hoạt ma trận --</option>
                  {TASK_TYPE_OPTIONS.map((opt, idx) => (
                    <option key={`create-type-opt-${opt.value}-${idx}`} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>

              {form.task_type && (
                <div className="matrix-container" style={{ gridColumn: '1 / -1' }}>
                  <div className="matrix-header-bar">
                    <strong>MA TRẬN PHÂN CÔNG (NHÂN CÔNG × AO NUÔI)</strong>
                  </div>
                  <div style={{ overflowX: 'auto', width: '100%' }}>
                    <table className="matrix-table-base">
                      <thead>
                        <tr>
                          <th className="matrix-th-worker" style={{ textAlign: 'left' }}>Nhân công / Ao nuôi</th>
                          {matrixPonds.map(p => (
                            <th key={`head-pond-${p.pond_id}`} className="matrix-th-pond" style={{ textAlign: 'center' }}>
                              {p.pond_name}
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {workers.map((w) => {
                          const wId = Number(w.worker_id || w.user_id || w.id);
                          const isBusy = normalize(w.work_status) === 'BUSY';
                          return (
                            <tr key={`row-worker-${wId}`} className={isBusy ? 'worker-busy' : ''}>
                              <td style={{ padding: '10px', border: '1px solid #e5e7eb' }}>
                                <div>
                                  <strong>{w.full_name || w.username}</strong>
                                  <div style={{ fontSize: '11px', color: isBusy ? 'red' : 'green' }}>
                                    {isBusy ? 'Đang bận' : 'Đang hoạt động'}
                                  </div>
                                </div>
                              </td>
                              {matrixPonds.map(p => {
                                const pId = Number(p.pond_id);
                                const isChecked = form.assignments.some(a => a.worker_id === wId && a.pond_id === pId);
                                return (
                                  <td key={`cell-${wId}-${pId}`} style={{ textAlign: 'center', border: '1px solid #e5e7eb' }}>
                                    <input
                                      type="checkbox"
                                      checked={isChecked}
                                      disabled={isBusy && !isChecked}
                                      onChange={() => toggleAssignment(wId, pId)}
                                    />
                                  </td>
                                );
                              })}
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                <label>Tiêu đề công việc mẫu</label>
                <input type="text" className="input" placeholder="Ví dụ: Kiểm tra định kỳ thông số môi trường nước..." value={form.task_title} onChange={(e) => setForm({ ...form, task_title: e.target.value })} />
              </div>

              <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                <label>Hướng dẫn kỹ thuật chi tiết chung <span style={{ color: 'red' }}>*</span></label>
                <textarea className="input" rows="3" placeholder="Nội dung hướng dẫn chi tiết..." value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} />
              </div>

              {isProductRequired && (
                <div style={{ gridColumn: '1 / -1', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', background: '#f0f9ff', padding: '12px', borderRadius: '8px', border: '1px dashed #0284c7' }}>
                  <div className="form-group">
                    <label>Vật tư chỉ định sử dụng</label>
                    <select className="input" value={form.product_id} onChange={(e) => setForm({ ...form, product_id: e.target.value })}>
                      <option value="">-- Chọn sản phẩm --</option>
                      {products.map((p, idx) => (
                        <option key={`create-prod-opt-${p.product_id}-${idx}`} value={p.product_id}>{p.product_name}</option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Số lượng định mức (cho mỗi ao)</label>
                    <input type="number" className="input" step="0.01" value={form.quantity} onChange={(e) => setForm({ ...form, quantity: e.target.value })} />
                  </div>
                </div>
              )}

              <div className="form-group">
                <label>Thời gian bắt đầu <span style={{ color: 'red' }}>*</span></label>
                <input type="datetime-local" className="input" value={form.start_date} onChange={(e) => setForm({ ...form, start_date: e.target.value })} />
              </div>

              <div className="form-group">
                <label>Hạn chót hoàn thành <span style={{ color: 'red' }}>*</span></label>
                <input type="datetime-local" className="input" value={form.due_date} onChange={(e) => setForm({ ...form, due_date: e.target.value })} />
              </div>
            </div>

            <div className="technician-seasons_actions" style={{ marginTop: '20px' }}>
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleCreateTask}
                disabled={form.assignments.length === 0 || !form.start_date || !form.due_date}
              >
                Xác nhận tạo {form.assignments.length} công việc
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default TechnicianTasks
